    {
      "findingType": "overpricing",
      "severity": "high",
      "description": "Inverter units priced 50% above market rate",
      "evidence": "Three independent quotes average LKR 80,000; contract price LKR 120,000",
      "recommendation": "Renegotiate or issue credit note"
    }
  ]
}

